@startuml
title ブリッジパターン

package "main" {
    class main
}

package "Bridge" {
    class Display {
        impl
        --
        open(arg): void
        print(arg): void
        close(arg): void
        display(arg): void
    }

    class CountDisplay {
        --
        multi_display(arg): void
    }

    class DisplayImpl {
        --
        raw_open(arg): void
        raw_print(arg): void
        raw_close(arg): void
    }

    class StringDisplayImpl {
        --
        raw_open(arg): void
        raw_print(arg): void
        raw_close(arg): void
    }
}

main --> Display : Uses
main --> CountDisplay : Uses
main --> StringDisplayImpl : Create

Display o--> DisplayImpl
CountDisplay --|> Display
StringDisplayImpl --|> DisplayImpl

@enduml
